// Simulate an external lookup to find the customer for this user and enrich our event with it. 
// Some users aren't found in the external system (master data sync issues). 
const USER_TO_CUSTOMER = {
    0: "Cool Cats",
    1: "Cool Cats",
    2: "Cool Cats",
    3: "Cool Cats",
    4: "Nova Brands",
    5: "Nova Brands",
    6: "Nova Brands",
    7: "Nova Brands",
    8: "CUSTOMER_NOT_FOUND",
    9: "Life-as-a-Service",
    10: "Life-as-a-Service",
    11: "Life-as-a-Service"
};

function enrichWithCustomer(event) {
    const customerId = USER_TO_CUSTOMER[event.userId] ?? "CUSTOMER_NOT_FOUND";
    return {
        customerId: customerId,
        ...event
    };
}

await push(enrichWithCustomer(payload));

// Normalize the input so it's easier to use downstream
payload.serviceName = payload.actionType.split(".")[0];
payload.operation = payload.actionType.split(".")[1];
delete payload.actionType;

await push(payload);

// Calculate AI token usage unit cost per operation. 
// Simple case here, but could be fetched from an external system to enrich as well.
function assignUnitCost() {
    let cost = 0;
    if (payload.serviceName == "AICopyWriter") {
        cost = payload.tokensUsed * 0.0001; 
    } else if (payload.serviceName == "MagicDesign") {
        if (payload.assetType == "image") {
            cost = payload.tokensUsed * 0.0002;
        } else if (payload.assetType == "video") {
            cost = payload.tokensUsed * 0.0003;
        }
    } else if (payload.serviceName == "AIBrandAgent") {
        cost = payload.tokensUsed * 0.0005;
    } else {
        payload.serviceName = "UNKNOWN: " + payload.ServiceName;
    }

    return Number(cost.toFixed(2)); // 2 decimals = Euro cents, for Previewability friendliness only - rounding should only be done on totals in production
}

await push({
    ...payload,
    aiUnitCost: assignUnitCost(payload),
    currency: "EUR",
});

if (state.node.count === undefined) {
    state.node.count = 0;
}

const simulatedUserEvent = {
    eventId: simEventId(),
    user: simUserId(),
    userAction: simActionType(),
    assetType: simAssetType(),
    assetId: simAssetId(),
    aiTokensUsed: simAiTokensUsed(),
    eventTimestamp: simDate()
};

state.node.count++;

// Some events are invalid
if (state.node.count % 10 === 3) {
    simulatedUserEvent.user = "INVALID";
}

await push(simulatedUserEvent);

// 20% of events are duplicates
if (state.node.count % 5 === 0) {
    simulatedUserEvent.userAction = "DUPLICATE";
    await push(simulatedUserEvent);
} 


function simUserId() {
    return Math.floor(Math.random() * 6) + Math.floor(Math.random() * 6);
}

function simEventId() {
    return Math.floor(Math.random() * 1000000);
}

function simAssetId() {
    return "AICopyWriter-" + state.node.count;
}

function simAiTokensUsed() {
    return 2000 + 200 * [Math.floor(Math.random() * 100)];
}

function simActionType() {
