// Simulate a lookup in an external publishing system
const publishedAssetIds = [
  "MagicDesign-0",
  "MagicDesign-2",
  "MagicDesign-5",
  "AICopyWriter-1",
  "AICopyWriter-3",
  "AICopyWriter-5",
  "AIBrandAgent-0",
  "AIBrandAgent-3",
  "AIBrandAgent-6"
];

// Only price published AI-generated assets and user actions, other non-published events are filtered out here
if (publishedAssetIds.includes(payload.assetId)) {
  payload.published = true;
  await push(payload);
}

// Assign credit weights depending on serviceName and assetType produced - some cost more than others. 
// This is a simple simulation, would be fetched from an cached reference data in production.
function assignCreditWeights() {
    let credits = 0;
    if (payload.serviceName == "AICopyWriter") {
        credits = 1;
    } else if (payload.serviceName == "MagicDesign") {
        if (payload.assetType == "image") {
            credits = 3;
        } else if (payload.assetType == "video") {
            credits = 4;
        }
    } else if (payload.serviceName == "AIBrandAgent") {
        credits = 5;
    } else {
        payload.serviceName = "UNKNOWN";
    }

    return credits;
}

await push({
